import tempfile, os
tmp = os.path.join(tempfile.mkdtemp(), 'testdb')
records = {
    'emp001': {'name': 'Alice', 'role': 'Engineer'},
    'emp002': {'name': 'Bob', 'role': 'Manager'},
    'emp003': {'name': 'Carol', 'role': 'Designer'}
}
store_records(tmp, records)
assert retrieve_record(tmp, 'emp001') == {'name': 'Alice', 'role': 'Engineer'}
assert retrieve_record(tmp, 'emp002') == {'name': 'Bob', 'role': 'Manager'}
assert retrieve_record(tmp, 'missing') is None
assert list_keys(tmp) == ['emp001', 'emp002', 'emp003']
store_records(tmp, {'emp004': {'name': 'Dave', 'role': 'Intern'}})
assert retrieve_record(tmp, 'emp004') == {'name': 'Dave', 'role': 'Intern'}
assert 'emp001' in list_keys(tmp)
